// STUB: Check for shifts starting in 1 hour
// In production, query the roster API for today's shifts
// and send reminders to staff whose shifts start soon
const now = new Date();
const nextHour = now.getHours() + 1;

let shiftType = null;
if (nextHour === 7) shiftType = 'MORNING';
else if (nextHour === 15) shiftType = 'EVENING';
else if (nextHour === 22) shiftType = 'NIGHT';

if (!shiftType) {
  return []; // No shift starting in next hour
}

return [{
  json: {
    message: `[STUB] Would send reminder for ${shiftType} shift starting at ${nextHour}:00`,
    shiftType: shiftType,
    reminderTime: now.toISOString()
  }
}];
